package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import java.lang.reflect.Method;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private static Method isLineBreakCharMethod;

    @BeforeAll
    static void setUp() throws Exception {
        isLineBreakCharMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakCharMethod.setAccessible(true);
    }

    @Test
    void testIsLineBreak_withLF() throws Exception {
        boolean result = (boolean) isLineBreakCharMethod.invoke(null, Character.valueOf('\n'));
        assertTrue(result, "LF (\\n) should be recognized as line break");
    }

    @Test
    void testIsLineBreak_withCR() throws Exception {
        boolean result = (boolean) isLineBreakCharMethod.invoke(null, Character.valueOf('\r'));
        assertTrue(result, "CR (\\r) should be recognized as line break");
    }

    @Test
    void testIsLineBreak_withOtherChar() throws Exception {
        boolean result = (boolean) isLineBreakCharMethod.invoke(null, Character.valueOf('a'));
        assertFalse(result, "'a' should not be recognized as line break");
    }

    @Test
    void testIsLineBreak_withSpace() throws Exception {
        boolean result = (boolean) isLineBreakCharMethod.invoke(null, Character.valueOf(' '));
        assertFalse(result, "Space should not be recognized as line break");
    }

    @Test
    void testIsLineBreak_withTab() throws Exception {
        boolean result = (boolean) isLineBreakCharMethod.invoke(null, Character.valueOf('\t'));
        assertFalse(result, "Tab should not be recognized as line break");
    }

    @Test
    void testIsLineBreak_withNullChar() throws Exception {
        boolean result = (boolean) isLineBreakCharMethod.invoke(null, Character.valueOf('\0'));
        assertFalse(result, "Null char should not be recognized as line break");
    }
}
